args.sparql:
SELECT (COUNT(?building) AS ?count)
WHERE {
  {
    SELECT ?site
    WHERE {
      ?site wdt:P31 wd:Q12168243 .  # NRHP site
      ?site wdt:P2541 wd:Q410756 .   # located along US Route 90
      ?site wdt:P577 ?date .
    }
    ORDER BY DESC(?date)
    LIMIT 1
  }
  ?site wdt:P527 ?building .
}

